import React, { useEffect, useState } from 'react';
import { useUser } from '../context/UserContext';

function AccountPage() {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [enable2FA, setEnable2FA] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);
  const [message, setMessage] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const { setUser } = useUser();

  // 🔹 Получение профиля
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) return;

    fetch('http://localhost:5001/api/user/profile', {
      headers: {
        Authorization: `Bearer ${token}`,
      },
      credentials: 'include',
    })
      .then(res => res.json())
      .then(data => {
        if (data.success) {
          setUsername(data.user.username);
          setEmail(data.user.email);
          setEnable2FA(data.user.is_2fa_enabled);
          setIsSubscribed(data.user.is_subscribed);
        } else {
          setMessage(data.message || 'Failed to load user profile');
        }
        setIsLoading(false);
      })
      .catch(() => {
        setMessage('Server error while loading profile');
        setIsLoading(false);
      });
  }, []);

  // 🔹 Сохранение профиля
  const handleSave = async () => {
    const token = localStorage.getItem('token');
    setIsSaving(true);
    setMessage('');

    try {
      const res = await fetch('http://localhost:5001/api/user/profile', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        credentials: 'include',
        body: JSON.stringify({ username, email }),
      });

      const data = await res.json();
      if (data.success) {
        setMessage(data.message);
        if (data.token && data.username) {
          setUser({ username: data.username }, data.token);
        }
      } else {
        setMessage(data.message || 'Update failed');
      }
    } catch {
      setMessage('Server error while updating profile');
    } finally {
      setIsSaving(false);
    }
  };

  // 🔹 Переключение 2FA
  const handleToggle2FA = async () => {
    const token = localStorage.getItem('token');
    setMessage('');

    try {
      const res = await fetch('http://localhost:5001/api/user/2fa/enable-disable', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        credentials: 'include',
        body: JSON.stringify({ enable_2fa: !enable2FA }),
      });

      const data = await res.json();
      if (data.success) {
        setEnable2FA(prev => !prev);
        setMessage(data.message);
      } else {
        setMessage(data.message || 'Failed to update 2FA');
      }
    } catch {
      setMessage('Server error while updating 2FA');
    }
  };

  // 🔹 Stripe подписка
  const handleSubscribe = async () => {
    const token = localStorage.getItem('token');
    setMessage('');

    try {
      const res = await fetch('http://localhost:5001/api/pay/create-checkout-session', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
        },
        credentials: 'include',
      });

      const data = await res.json();
      if (data.url) {
        window.location.href = data.url;
      } else {
        setMessage(data.error || 'Failed to start subscription process');
      }
    } catch (err) {
      setMessage('Server error during subscription');
    }
  };

  // 🔹 Показываем спиннер при загрузке
  if (isLoading) {
    return (
      <div className="container py-5 text-center">
        <div className="spinner-border text-primary" role="status" />
      </div>
    );
  }

return (
  <div className="container py-5" style={{ maxWidth: '1000px' }}>
    <div className="row g-4">
      {/* Левая колонка — профиль */}
      <div className="col-md-5">
        <div className="card shadow-sm rounded-4 p-4">
          <h4 className="mb-4 fw-bold">Account Settings</h4>

          {message && <div className="alert alert-info">{message}</div>}

          <div className="mb-3">
            <label className="form-label">Username</label>
            <input
              type="text"
              className="form-control"
              value={username}
              onChange={e => setUsername(e.target.value)}
            />
          </div>

          <div className="mb-3">
            <label className="form-label">Email</label>
            <input
              type="email"
              className="form-control"
              value={email}
              onChange={e => setEmail(e.target.value)}
            />
          </div>

          <div className="form-check form-switch mb-4">
            <input
              className="form-check-input"
              type="checkbox"
              checked={enable2FA}
              onChange={handleToggle2FA}
              id="enable2FA"
            />
            <label className="form-check-label" htmlFor="enable2FA">
              Enable Two-Factor Authentication (2FA)
            </label>
          </div>

          <button
            onClick={handleSave}
            className="btn btn-primary w-100"
            disabled={isSaving}
          >
            {isSaving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>

      {/* Правая колонка — подписка */}
<div className="col-md-7">
  {!isSubscribed ? (
    <div className="premium-container p-4 shadow-lg rounded-4">
      <h4 className="mb-4 text-center fw-bold fs-3 text-gradient">🚀 Unlock Premium Features</h4>

      <div className="row row-cols-1 row-cols-md-2 g-4">

        {/* INDIVIDUAL PLAN */}
        <div className="col">
          <div className="premium-card premium-highlight p-4 h-100 border-0">
            <div className="badge bg-primary-subtle text-primary-emphasis mb-2 w-fit">🔥 Best for Solo</div>
            <h5 className="fw-bold mb-1 fs-5">🎧 Premium Individual</h5>
            <p className="text-muted mb-3">€5.00 / month</p>
            <ul className="list-unstyled mb-4">
              <li>✔️ 1 Premium account</li>
              <li>✔️ Weekly AI travel plans</li>
              <li>✔️ Voting access & early features</li>
              <li>✔️ Cancel anytime</li>
            </ul>
            <button onClick={handleSubscribe} className="btn btn-success w-100 shadow-sm">
              Get Premium
            </button>
          </div>
        </div>

        {/* DUO PLAN */}
        <div className="col">
          <div className="premium-card p-4 h-100 border-0 opacity-75">
            <div className="badge bg-secondary-subtle text-secondary-emphasis mb-2 w-fit">Coming Soon</div>
            <h5 className="fw-bold mb-1 fs-5">👥 Premium Duo</h5>
            <p className="text-muted mb-3">€8.00 / month</p>
            <ul className="list-unstyled mb-4">
              <li>✔️ 2 Premium accounts</li>
              <li>✔️ For couples or roommates</li>
              <li>✔️ AI travel shared planner</li>
              <li>✔️ Cancel anytime</li>
            </ul>
            <button disabled className="btn btn-outline-secondary w-100" title="Coming soon">
              Coming Soon
            </button>
          </div>
        </div>

      </div>
    </div>
  ) : (
    <div className="alert alert-success mt-3">
      You are a Premium user 🎉
    </div>
  )}
</div>

    </div>
  </div>
);

}

export default AccountPage;
